import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import he from '../i18n/he.json';

const API = 'https://pizza-story-backend-u6n0.onrender.com';
const DELIVERY_FEE = 15;
const STORE_ADDRESS = 'רחוב הפיצה 1, תל אביב';

const PROMO_CODES = {
  PIZZA10:  { type: 'percent',  value: 10, label: '10% הנחה' },
  PIZZA20:  { type: 'percent',  value: 20, label: '20% הנחה' },
  FREESHIP: { type: 'delivery', value: 0,  label: 'משלוח חינם' },
};

export default function CheckoutForm() {
  const navigate = useNavigate();
  const cart = JSON.parse(localStorage.getItem('cart') || '{}');
  const auth = JSON.parse(localStorage.getItem('pizzaAuth') || '{}');

  const [form, setForm] = useState({
    name:         auth.name || '',
    phone:        auth.phone || '',
    address:      '',
    kitchenNotes: '',
    driverNotes:  '',
    paymentMethod: 'cash',
  });
  const [fulfillmentType, setFulfillmentType] = useState('delivery');
  const [promoInput,      setPromoInput]      = useState('');
  const [appliedPromo,    setAppliedPromo]    = useState(null);
  const [promoError,      setPromoError]      = useState('');
  const [addressPrefilled, setAddressPrefilled] = useState(false);
  const [loading,         setLoading]         = useState(false);

  // Pre-fill address and name from last order
  useEffect(() => {
    if (!auth.phone) return;
    axios
      .get(`${API}/api/orders/history/${auth.phone}`)
      .then(res => {
        const sorted = res.data.sort(
          (a, b) => new Date(b.createdAt) - new Date(a.createdAt)
        );
        const last = sorted[0];
        if (!last) return;
        const lastAddress = last.address || last.deliveryAddress;
        if (lastAddress) {
          setForm(f => ({ ...f, address: lastAddress }));
          setAddressPrefilled(true);
        }
        if (last.name && !auth.name) {
          setForm(f => ({ ...f, name: last.name }));
        }
      })
      .catch(() => {});
  }, []);

  if (!cart.toppings) return null;

  const handleChange = e =>
    setForm(f => ({ ...f, [e.target.name]: e.target.value }));

  const applyPromo = () => {
    const code = promoInput.trim().toUpperCase();
    if (PROMO_CODES[code]) {
      setAppliedPromo({ code, ...PROMO_CODES[code] });
      setPromoError('');
    } else {
      setPromoError(he.promo_invalid);
      setAppliedPromo(null);
    }
  };

  const removePromo = () => {
    setAppliedPromo(null);
    setPromoInput('');
    setPromoError('');
  };

  // Price calculation
  const baseTotal   = cart.total || 30;
  const isFreeShip  = appliedPromo?.type === 'delivery';
  const deliveryFee = fulfillmentType === 'delivery' && !isFreeShip ? DELIVERY_FEE : 0;
  const discountAmt = appliedPromo?.type === 'percent'
    ? Math.round(baseTotal * appliedPromo.value / 100)
    : 0;
  const finalTotal = baseTotal + deliveryFee - discountAmt;

  const handleSubmit = async e => {
    e.preventDefault();
    if (fulfillmentType === 'delivery' && !form.address.trim()) {
      alert('יש להכניס כתובת למשלוח');
      return;
    }
    setLoading(true);
    try {
      await axios.post(`${API}/api/orders`, {
        name:           form.name,
        phone:          form.phone,
        customerPhone:  form.phone,
        address:        fulfillmentType === 'delivery' ? form.address : STORE_ADDRESS,
        deliveryAddress: fulfillmentType === 'delivery' ? form.address : '',
        paymentMethod:  form.paymentMethod,
        paymentStatus:  form.paymentMethod === 'cash' ? 'pending_cash' : 'paid',
        fulfillmentType,
        kitchenNotes:   form.kitchenNotes || null,
        driverNotes:    fulfillmentType === 'delivery' ? (form.driverNotes || null) : null,
        couponCode:     appliedPromo?.code || null,
        toppings:       cart.toppings,
        total:          finalTotal,
        createdAt:      new Date().toISOString(),
      });

      // Persist name to auth for future pre-fill
      if (form.name && !auth.name) {
        localStorage.setItem(
          'pizzaAuth',
          JSON.stringify({ ...auth, name: form.name })
        );
      }

      localStorage.removeItem('cart');
      navigate('/success');
    } catch {
      alert('שגיאה בשליחת ההזמנה');
    } finally {
      setLoading(false);
    }
  };

  return (
    <form
      onSubmit={handleSubmit}
      className="max-w-md mx-auto mt-6 pb-10"
    >
      {/* Header */}
      <div className="bg-tomato text-white px-5 py-4 rounded-t-2xl">
        <h2 className="text-xl font-bold text-center">🛵 {he.checkout}</h2>
      </div>

      <div className="bg-white px-5 py-5 rounded-b-2xl shadow-lg space-y-4">

        {/* Fulfillment Toggle */}
        <div>
          <label className="block mb-2 font-semibold text-gray-700">
            {he.fulfillment_type}
          </label>
          <div className="flex rounded-xl overflow-hidden border border-gray-200">
            <button
              type="button"
              onClick={() => setFulfillmentType('delivery')}
              className={`flex-1 py-3 font-bold text-sm transition
                ${fulfillmentType === 'delivery'
                  ? 'bg-tomato text-white'
                  : 'bg-gray-50 text-gray-600 hover:bg-gray-100'}`}
            >
              🛵 {he.delivery_label}
            </button>
            <button
              type="button"
              onClick={() => setFulfillmentType('pickup')}
              className={`flex-1 py-3 font-bold text-sm transition
                ${fulfillmentType === 'pickup'
                  ? 'bg-tomato text-white'
                  : 'bg-gray-50 text-gray-600 hover:bg-gray-100'}`}
            >
              🏪 {he.pickup}
            </button>
          </div>
          {fulfillmentType === 'pickup' && (
            <div className="mt-2 bg-orange-50 border border-orange-100 rounded-xl p-3 text-sm text-gray-600">
              📍 {he.store_address}
            </div>
          )}
        </div>

        {/* Name */}
        <div>
          <label className="block mb-1 font-medium text-gray-700">{he.name}</label>
          <input
            name="name"
            value={form.name}
            onChange={handleChange}
            required
            className="w-full border rounded-xl px-3 py-2.5 focus:outline-none focus:border-tomato transition"
          />
        </div>

        {/* Phone */}
        <div>
          <label className="block mb-1 font-medium text-gray-700">{he.phone}</label>
          <input
            name="phone"
            type="tel"
            value={form.phone}
            onChange={handleChange}
            required
            className="w-full border rounded-xl px-3 py-2.5 focus:outline-none focus:border-tomato transition"
            dir="ltr"
          />
        </div>

        {/* Address — delivery only */}
        {fulfillmentType === 'delivery' && (
          <div>
            <label className="block mb-1 font-medium text-gray-700">{he.address}</label>
            <input
              name="address"
              value={form.address}
              onChange={handleChange}
              required
              placeholder="רחוב, מספר, עיר"
              className="w-full border rounded-xl px-3 py-2.5 focus:outline-none focus:border-tomato transition"
            />
            {addressPrefilled && (
              <p className="text-xs text-gray-400 mt-1">✓ מולאה מהזמנה קודמת</p>
            )}
          </div>
        )}

        {/* Kitchen Notes */}
        <div>
          <label className="block mb-1 font-medium text-gray-700">{he.kitchen_notes}</label>
          <textarea
            name="kitchenNotes"
            value={form.kitchenNotes}
            onChange={handleChange}
            rows={2}
            placeholder="לדוגמה: ללא גלוטן, לא חריף..."
            className="w-full border rounded-xl px-3 py-2.5 focus:outline-none focus:border-tomato transition resize-none text-sm"
          />
        </div>

        {/* Driver Notes — delivery only */}
        {fulfillmentType === 'delivery' && (
          <div>
            <label className="block mb-1 font-medium text-gray-700">{he.driver_notes}</label>
            <textarea
              name="driverNotes"
              value={form.driverNotes}
              onChange={handleChange}
              rows={2}
              placeholder="לדוגמה: קומה 3, אינטרקום 12, לא לצלצל..."
              className="w-full border rounded-xl px-3 py-2.5 focus:outline-none focus:border-tomato transition resize-none text-sm"
            />
          </div>
        )}

        {/* Promo Code */}
        <div>
          <label className="block mb-1 font-medium text-gray-700">{he.promo_code}</label>
          {appliedPromo ? (
            <div className="flex items-center gap-2 bg-green-50 border border-green-200 rounded-xl px-3 py-2.5">
              <span className="text-green-700 text-sm font-bold flex-1">
                ✓ {appliedPromo.label} ({appliedPromo.code})
              </span>
              <button
                type="button"
                onClick={removePromo}
                className="text-gray-400 text-xs hover:text-red-500 transition"
              >
                הסר
              </button>
            </div>
          ) : (
            <div className="flex gap-2">
              <input
                value={promoInput}
                onChange={e => { setPromoInput(e.target.value); setPromoError(''); }}
                onKeyDown={e => e.key === 'Enter' && (e.preventDefault(), applyPromo())}
                placeholder="הכנס קוד..."
                className="flex-1 border rounded-xl px-3 py-2.5 focus:outline-none focus:border-tomato transition text-sm uppercase"
                dir="ltr"
              />
              <button
                type="button"
                onClick={applyPromo}
                className="bg-gray-100 hover:bg-gray-200 px-4 rounded-xl text-sm font-bold text-gray-700 transition"
              >
                החל
              </button>
            </div>
          )}
          {promoError && <p className="text-red-500 text-xs mt-1">{promoError}</p>}
          <p className="text-xs text-gray-400 mt-1">קודות לדוגמה: PIZZA10 | PIZZA20 | FREESHIP</p>
        </div>

        {/* Payment Method */}
        <div>
          <label className="block mb-2 font-semibold text-gray-700">{he.payment_method}</label>
          <div className="flex gap-3">
            <label
              className={`flex-1 flex items-center justify-center gap-2 p-3 rounded-xl border-2 cursor-pointer transition
                ${form.paymentMethod === 'cash' ? 'border-tomato bg-red-50' : 'border-gray-200'}`}
            >
              <input
                type="radio"
                name="paymentMethod"
                value="cash"
                checked={form.paymentMethod === 'cash'}
                onChange={handleChange}
                className="hidden"
              />
              <span className="text-xl">💵</span>
              <span className="font-medium text-sm">
                {fulfillmentType === 'pickup' ? 'מזומן בעסק' : 'מזומן לשליח'}
              </span>
            </label>
            <label
              className={`flex-1 flex items-center justify-center gap-2 p-3 rounded-xl border-2 cursor-pointer transition
                ${form.paymentMethod === 'credit' ? 'border-tomato bg-red-50' : 'border-gray-200'}`}
            >
              <input
                type="radio"
                name="paymentMethod"
                value="credit"
                checked={form.paymentMethod === 'credit'}
                onChange={handleChange}
                className="hidden"
              />
              <span className="text-xl">💳</span>
              <span className="font-medium text-sm">כרטיס אשראי</span>
            </label>
          </div>
          {form.paymentMethod === 'cash' && (
            <p className="text-xs text-gray-400 mt-1 text-center">
              התשלום יבוצע {fulfillmentType === 'pickup' ? 'בעת האיסוף' : 'בקבלת ההזמנה'}
            </p>
          )}
        </div>

        {/* Price Breakdown */}
        <div className="bg-gray-50 rounded-xl p-4 space-y-2">
          <div className="flex justify-between text-sm text-gray-600">
            <span>🍕 פיצה + תוספות</span>
            <span>{baseTotal}₪</span>
          </div>
          {fulfillmentType === 'delivery' && (
            <div className="flex justify-between text-sm text-gray-600">
              <span>🛵 {he.delivery_fee}</span>
              <span>
                {isFreeShip ? (
                  <span className="flex items-center gap-1">
                    <span className="line-through text-gray-400">{DELIVERY_FEE}₪</span>
                    <span className="text-green-600 font-bold">חינם!</span>
                  </span>
                ) : (
                  `${DELIVERY_FEE}₪`
                )}
              </span>
            </div>
          )}
          {discountAmt > 0 && (
            <div className="flex justify-between text-sm text-green-600 font-medium">
              <span>🏷️ {he.discount} ({appliedPromo.code})</span>
              <span>-{discountAmt}₪</span>
            </div>
          )}
          <div className="flex justify-between font-bold text-xl pt-2 border-t border-gray-200">
            <span>{he.total}</span>
            <span className="text-tomato">{finalTotal}₪</span>
          </div>
        </div>

        {/* Submit */}
        <button
          type="submit"
          disabled={loading}
          className="w-full bg-tomato text-white py-3.5 rounded-xl font-bold text-lg hover:bg-red-700 transition shadow-md"
        >
          {loading ? 'שולח...' : `${he.place_order} • ${finalTotal}₪`}
        </button>
      </div>
    </form>
  );
}
